```powershell
# Measure-Command : mesurer le temps d'exécution
$temps = Measure-Command {
    1..10000 | ForEach-Object { $_ * $_ }
}
Write-Host "Durée : $($temps.TotalMilliseconds)ms"

# Comparer des approches
function Compare-Approches {
    param(
        [hashtable]$Approches,
        [int]$Iterations = 3
    )

    $results = foreach ($nom in $Approches.Keys) {
        $durees = 1..$Iterations | ForEach-Object {
            (Measure-Command $Approches[$nom]).TotalMilliseconds
        }
        [PSCustomObject]@{
            Nom       = $nom
            Moy_ms    = [math]::Round(($durees | Measure-Object -Average).Average, 2)
            Min_ms    = [math]::Round(($durees | Measure-Object -Minimum).Minimum, 2)
        }
    }
    $results | Sort-Object Moy_ms | Format-Table
}

Compare-Approches @{
    'Pipeline'  = { 1..1000 | ForEach-Object { $_ * 2 } }
    'Foreach'   = { $r = @(); foreach($i in 1..1000){ $r += $i*2 }; $r }
    'Tableau'   = { [int[]]$r = 1..1000; for($i=0;$i-lt1000;$i++){$r[$i]*=2}; $r }
}
```

```powershell
# RunspacePool pour un parallélisme fin
$pool = [runspacefactory]::CreateRunspacePool(1, [Environment]::ProcessorCount)
$pool.Open()

$jobs = 1..10 | ForEach-Object {
    $n = $_
    $ps = [PowerShell]::Create()
    $ps.RunspacePool = $pool

    [void]$ps.AddScript({
        param($n)
        Start-Sleep -Milliseconds (Get-Random -Max 500)
        "Résultat de $n : $($n * $n)"
    }).AddArgument($n)

    @{ PS = $ps; Result = $ps.BeginInvoke() }
}

# Récupérer les résultats
$jobs | ForEach-Object {
    $_.PS.EndInvoke($_.Result)
    $_.PS.Dispose()
}

$pool.Close()
$pool.Dispose()

# Task async .NET
$task = [System.Threading.Tasks.Task]::Run({
    Start-Sleep 1
    "Fait!"
})
$task.Wait()
$task.Result
```

```powershell
# Surveiller l'utilisation mémoire
function Get-MemUsage {
    $proc = [System.Diagnostics.Process]::GetCurrentProcess()
    [PSCustomObject]@{
        WorkingSet_MB  = [math]::Round($proc.WorkingSet64/1MB, 1)
        Private_MB     = [math]::Round($proc.PrivateMemorySize64/1MB, 1)
        GC_Gen0        = [GC]::CollectionCount(0)
        GC_Gen1        = [GC]::CollectionCount(1)
        GC_Gen2        = [GC]::CollectionCount(2)
        TotalMemory_MB = [math]::Round([GC]::GetTotalMemory($false)/1MB, 1)
    }
}

# Forcer le GC (utile pour les tests)
[GC]::Collect()
[GC]::WaitForPendingFinalizers()

# Détecter les fuites mémoire
$baseline = Get-MemUsage
for ($i = 0; $i -lt 5; $i++) {
    # Simuler une opération
    $data = 1..100000 | ForEach-Object { [PSCustomObject]@{N=$_} }
    $data = $null  # libérer la référence
    [GC]::Collect()

    $current = Get-MemUsage
    Write-Host "Itération $i — RAM: $($current.WorkingSet_MB)Mo"
}

# IDisposable
$stream = [System.IO.FileStream]::new('C:\temp\test.bin', 'Create')
try {
    $stream.WriteByte(65)
} finally {
    $stream.Dispose()  # ou $stream.Close()
}
