$fragments = 1..1000 | ForEach-Object { "item$_ " }

$t1 = Measure-Command {
    $s1 = ""
    foreach ($f in $fragments) { $s1 += $f }
}

$t2 = Measure-Command {
    $sb = [System.Text.StringBuilder]::new()
    foreach ($f in $fragments) { [void]$sb.Append($f) }
    $s2 = $sb.ToString()
}

